    invariant rightDone ==> 0 <= ri < m
    invariant rightDone ==> exists r | 0 <= r < n :: grid[r][ri] == '*'
    invariant rightDone ==> forall r | 0 <= r < n :: forall c | ri < c < m :: grid[r][c] != '*'
    decreases ri + 1, !rightDone
